    @Description("TC-21: Verify that login works with valid credentials")
    public void tc21_verifyLoginWithValidCredentials() {
        Allure.step("Navigate to login page", () -> {
            loginPage.navigateToLoginPage();
        });

        Allure.step("Verify login page elements are displayed", () -> {
            loginPage.verifyLoginPageLoaded();
            loginPage.verifyLoginElementsPresent();
        });

        Allure.step("Enter valid username", () -> {
            String username = loginPage.getCredentialByRole("Admin", "Username");
            loginPage.enterUsername(username);
        });

        Allure.step("Enter valid password", () -> {
            String password = loginPage.getCredentialByRole("Admin", "Password");
            loginPage.enterPassword(password);
        });

        Allure.step("Click login button", () -> {
            loginPage.clickLoginButton();
        });

        Allure.step("Verify user login successfully", () -> {
            loginPage.verifyLoginSuccess();
        });
    }

